#include<bits/stdc++.h>
using namespace std;
int max1[500010];
int n,k;
long long ans;
vector<int> mp[500010];
void dfs(int x,int fa=-1)
{
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            dfs(i,x);
            max1[x]=max(max1[x],max1[i]+1);
        }
    }
    if(max1[x]==0)
    {
        return;
    }
    ans+=k;
    for(int i:mp[x])
    {
        if(i!=fa)
        {
            if(max1[i]==max1[x]-1)
            {
                ans--;
            }
        }
    }
}
int main()
{
    scanf("%d%d",&n,&k);
    for(int i=1;i<n;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(v);
        mp[v].push_back(u);
    }
    dfs(1);
    printf("%d %lld",max1[1],ans);
    return 0;
}
